class Solution:
    def maximumCostSubstring(self, s: str, chars: str, vals: List[int]) -> int:
        max_cost = 0
        for i in range(len(s)):
            for j in range(i, len(s)):
                substring = s[i:j+1]
                cost = 0
                for char in substring:
                    if char in chars:
                        cost += vals[chars.index(char)]
                    else:
                        cost += ord(char) - ord('a') + 1
                max_cost = max(max_cost, cost)
        return max_cost
